mapper.select:
SELECT o.id, o.order_no AS orderNo, o.user_id AS userId, o.order_status AS orderStatus, o.pay_status AS payStatus, o.source_type AS sourceType, o.total_amount AS totalAmount, o.pay_amount AS payAmount, o.item_count AS itemCount, o.expire_time AS expireTime, o.pay_time AS payTime, o.create_time AS createTime FROM oms_order o
o.deleted = 0
AND o.order_no = #{param.orderNo}
AND o.user_id = #{param.userId}
AND o.order_status = #{param.orderStatus}
AND o.pay_status = #{param.payStatus}
AND o.create_time >= CONCAT(#{param.createTimeStart}, ' 00:00:00')
AND o.create_time <= CONCAT(#{param.createTimeEnd}, ' 23:59:59')
ORDER BY o.create_time DESC
